from sympy import primerange
def sequence(limit):
    results = []
    for p in primerange(3, limit):
        q = ((pow(2, p - 1, p**2) - 1) // p) % p
        if q > 1 and (p - 1) % q == 0:
            results.append(p)
    return results
print(sequence(3000000))

